// var hoists with undefined initializer
console.log(a);  // undefined  (not ReferenceError)
var a = 5;

// function declarations hoist fully
greet();         // 'hi'
function greet() { console.log('hi'); }

// let/const hoist into TDZ — throw if accessed early
console.log(b);  // ReferenceError: Cannot access 'b' before initialization
let b = 5;

function makeCounter() {
  let count = 0;
  return () => ++count; // closes over count
}
const c = makeCounter();
c(); // 1
c(); // 2

const arr = [1, 2, 3];
const newArr = [...arr, 4];  // [1, 2, 3, 4] — new array
// arr is unchanged: [1, 2, 3]

const obj = { x: 1 };
const newObj = { ...obj, y: 2 };  // immutable update

function fetchData(callback) {
  setTimeout(() => {
    callback({ data: "result" });
  }, 1000);
}

fetchData((result) => {
  console.log(result.data);  // 'result' after 1s
});

fetch('/api/users')
  .then(res => res.json())
  .then(data => console.log(data))
  .catch(err => console.error(err));

// modern:
const data = await fetch('/api/users').then(r => r.json());

async function getUser(id: string): Promise<User> {
  const res = await fetch(`/api/users/${id}`);
  const user = await res.json();
  return user;
}

const user = await getUser('42');

// Static typing:
function add(a: number, b: number): number {
  return a + b;
}

add(1, 2);      // ✅ 3
add(1, "2");    // ❌ Type error at compile time

interface Logger {
  log(message: string): void;
}

class ConsoleLogger implements Logger {
  log(message: string) {
    console.log(message);
  }
}

// Uncurried
const add = (a, b) => a + b;
add(2, 3);  // 5

// Curried
const addCurried = a => b => a + b;
add(2)(3);  // 5

// Partial application
const addTwo = addCurried(2);
[1, 2, 3].map(addTwo);  // [3, 4, 5]
